"""Tests for the CI workflow generator — stdlib unittest only."""

from __future__ import annotations

import subprocess
import sys
import tomllib
import unittest
from pathlib import Path

# Import the generator module.
sys.path.insert(0, str(Path(__file__).resolve().parent.parent))
from generate_ci import (
    IOS_VARIANTS,
    MANIFEST,
    OUTFILE,
    _matches_token,
    _token_to_expr,
    emit_if,
    eval_condition,
    generate,
)

# ── Helpers ─────────────────────────────────────────────────────────────


def _steps_for_variant(variant: str) -> set[str]:
    """Return the set of step names that run for *variant*."""
    with open(MANIFEST, "rb") as f:
        data = tomllib.load(f)
    names: set[str] = set()
    for step in data["steps"]:
        if eval_condition(variant, step.get("only", [])):
            names.add(step.get("name", step["run"]))
    return names


# ── _matches_token ──────────────────────────────────────────────────────


class MatchesTokenTest(unittest.TestCase):
    def test_exact_variant(self) -> None:
        self.assertTrue(_matches_token("linux-x64-vulkan", "linux-x64-vulkan"))
        self.assertFalse(_matches_token("linux-x64-egl", "linux-x64-vulkan"))

    def test_negated_variant(self) -> None:
        self.assertFalse(_matches_token("linux-x64-vulkan", "!linux-x64-vulkan"))
        self.assertTrue(_matches_token("linux-x64-egl", "!linux-x64-vulkan"))

    def test_not_ios(self) -> None:
        self.assertTrue(_matches_token("linux-x64-vulkan", "not_ios"))
        self.assertTrue(_matches_token("macos-arm64-metal", "not_ios"))
        for ios in IOS_VARIANTS:
            self.assertFalse(_matches_token(ios, "not_ios"), msg=ios)

    def test_not_ios_negated(self) -> None:
        for ios in IOS_VARIANTS:
            self.assertTrue(_matches_token(ios, "!not_ios"), msg=ios)
        self.assertFalse(_matches_token("linux-x64-vulkan", "!not_ios"))

    def test_not_macos_arm64_egl(self) -> None:
        self.assertTrue(_matches_token("macos-arm64-metal", "not_macos_arm64_egl"))
        self.assertFalse(_matches_token("macos-arm64-egl", "not_macos_arm64_egl"))

    def test_vulkan_only(self) -> None:
        self.assertTrue(_matches_token("linux-x64-vulkan", "vulkan_only"))
        self.assertTrue(_matches_token("macos-arm64-vulkan", "vulkan_only"))
        self.assertFalse(_matches_token("linux-x64-egl", "vulkan_only"))
        self.assertFalse(_matches_token("macos-arm64-metal", "vulkan_only"))

    def test_macos_only(self) -> None:
        self.assertTrue(_matches_token("macos-arm64-metal", "macos_only"))
        self.assertTrue(_matches_token("macos-arm64-egl", "macos_only"))
        self.assertFalse(_matches_token("linux-x64-vulkan", "macos_only"))

    def test_not_windows(self) -> None:
        self.assertTrue(_matches_token("linux-x64-vulkan", "not_windows"))
        self.assertFalse(_matches_token("windows-x64-vulkan", "not_windows"))

    def test_not_linux_arm64(self) -> None:
        self.assertTrue(_matches_token("linux-x64-vulkan", "not_linux_arm64"))
        self.assertFalse(_matches_token("linux-arm64-vulkan", "not_linux_arm64"))


# ── eval_condition ──────────────────────────────────────────────────────


class EvalConditionTest(unittest.TestCase):
    def test_empty_tokens(self) -> None:
        self.assertTrue(eval_condition("anything", []))

    def test_and_semantics(self) -> None:
        self.assertTrue(
            eval_condition("macos-arm64-metal", ["not_ios", "not_macos_arm64_egl"])
        )
        self.assertFalse(
            eval_condition("ios-arm64-metal", ["not_ios", "not_macos_arm64_egl"])
        )
        self.assertFalse(
            eval_condition("macos-arm64-egl", ["not_ios", "not_macos_arm64_egl"])
        )


# ── _token_to_expr ─────────────────────────────────────────────────────


class TokenToExprTest(unittest.TestCase):
    def test_not_ios(self) -> None:
        self.assertEqual(
            _token_to_expr("not_ios"), "!startsWith(matrix.mise_env, 'ios-')"
        )
        self.assertEqual(
            _token_to_expr("!not_ios"), "startsWith(matrix.mise_env, 'ios-')"
        )

    def test_not_macos_arm64_egl(self) -> None:
        self.assertEqual(
            _token_to_expr("not_macos_arm64_egl"),
            "matrix.mise_env != 'macos-arm64-egl'",
        )
        self.assertEqual(
            _token_to_expr("!not_macos_arm64_egl"),
            "matrix.mise_env == 'macos-arm64-egl'",
        )

    def test_vulkan_only(self) -> None:
        self.assertEqual(
            _token_to_expr("vulkan_only"), "contains(matrix.mise_env, 'vulkan')"
        )
        self.assertEqual(
            _token_to_expr("!vulkan_only"), "!contains(matrix.mise_env, 'vulkan')"
        )

    def test_exact_variant(self) -> None:
        self.assertEqual(
            _token_to_expr("macos-arm64-metal"),
            "matrix.mise_env == 'macos-arm64-metal'",
        )
        self.assertEqual(
            _token_to_expr("!macos-arm64-metal"),
            "matrix.mise_env != 'macos-arm64-metal'",
        )


# ── emit_if ─────────────────────────────────────────────────────────────


class EmitIfTest(unittest.TestCase):
    def test_empty(self) -> None:
        self.assertEqual(emit_if([]), "")

    def test_single_condition(self) -> None:
        self.assertEqual(
            emit_if(["not_ios"]),
            "if: ${{ !startsWith(matrix.mise_env, 'ios-') }}",
        )

    def test_conjunction_ordering(self) -> None:
        # not_macos_arm64_egl must come first (matches original ci.yml order).
        result = emit_if(["not_macos_arm64_egl", "not_ios"])
        self.assertEqual(
            result,
            "if: ${{ matrix.mise_env != 'macos-arm64-egl' && !startsWith(matrix.mise_env, 'ios-') }}",
        )

    def test_swift_binding_condition(self) -> None:
        result = emit_if(["not_macos_arm64_egl", "macos_only"])
        self.assertEqual(
            result,
            "if: ${{ matrix.mise_env != 'macos-arm64-egl' && startsWith(matrix.mise_env, 'macos-') }}",
        )

    def test_kotlin_condition(self) -> None:
        result = emit_if(
            ["not_macos_arm64_egl", "not_ios", "not_windows", "not_linux_arm64"]
        )
        self.assertEqual(
            result,
            "if: ${{ matrix.mise_env != 'macos-arm64-egl' && !startsWith(matrix.mise_env, 'ios-') "
            "&& !startsWith(matrix.mise_env, 'windows-') && !startsWith(matrix.mise_env, 'linux-arm64-') }}",
        )


# ── generate: round-trip ────────────────────────────────────────────────


class GenerateRoundTripTest(unittest.TestCase):
    def test_matches_checked_in_workflow(self) -> None:
        """The generator must reproduce the checked-in ci.yml exactly."""
        expected = OUTFILE.read_text()
        actual = generate(MANIFEST)
        self.assertEqual(actual, expected)


# ── Variant step coverage ───────────────────────────────────────────────


class VariantStepCoverageTest(unittest.TestCase):
    """Each variant runs exactly the steps the policy intends."""

    def test_ios_arm64_metal(self) -> None:
        # iOS: only configure + build (cross-compile, no host runtime).
        self.assertEqual(
            _steps_for_variant("ios-arm64-metal"),
            {"Configure", "Build native library"},
        )

    def test_ios_simulator(self) -> None:
        self.assertEqual(
            _steps_for_variant("ios-simulator-arm64-metal"),
            {"Configure", "Build native library"},
        )

    def test_macos_arm64_egl(self) -> None:
        # macos-arm64-egl: native + Zig binding + readback only.
        self.assertEqual(
            _steps_for_variant("macos-arm64-egl"),
            {
                "Configure",
                "Test native library",
                "Test Zig binding",
                "Run Zig readback example",
            },
        )

    def test_linux_x64_vulkan_full(self) -> None:
        # Full desktop variant: everything except Swift and macOS-only example.
        self.assertEqual(
            _steps_for_variant("linux-x64-vulkan"),
            {
                "Configure",
                "Test native library",
                "Build Java FFM binding",
                "Build Java JNI binding",
                "Test .NET binding",
                "Test Kotlin/Native binding",
                "Test Rust binding",
                "Test Zig binding",
                "Build LWJGL example",
                "Test Rust example",
                "Build Zig example",
                "Run Zig readback example",
            },
        )

    def test_macos_arm64_metal_includes_swift(self) -> None:
        # macos-arm64-metal: the only variant with Swift binding + example.
        steps = _steps_for_variant("macos-arm64-metal")
        self.assertIn("Test Swift binding", steps)
        self.assertIn("Build Swift example", steps)
        self.assertNotIn("Build LWJGL example", steps)

    def test_windows_excludes_kotlin(self) -> None:
        steps = _steps_for_variant("windows-x64-vulkan")
        self.assertNotIn("Test Kotlin/Native binding", steps)

    def test_linux_arm64_excludes_kotlin(self) -> None:
        steps = _steps_for_variant("linux-arm64-egl")
        self.assertNotIn("Test Kotlin/Native binding", steps)

    def test_vulkan_variants_include_lwjgl(self) -> None:
        for v in ("linux-x64-vulkan", "linux-arm64-vulkan", "macos-arm64-vulkan"):
            with self.subTest(variant=v):
                self.assertIn("Build LWJGL example", _steps_for_variant(v))

    def test_non_vulkan_variants_exclude_lwjgl(self) -> None:
        for v in ("linux-x64-egl", "macos-arm64-metal", "windows-x64-wgl"):
            with self.subTest(variant=v):
                self.assertNotIn("Build LWJGL example", _steps_for_variant(v))

    def test_readback_runs_everywhere_except_ios(self) -> None:
        with open(MANIFEST, "rb") as f:
            data = tomllib.load(f)
        for entry in data["matrix"]:
            v = entry["mise_env"]
            steps = _steps_for_variant(v)
            if v.startswith("ios-"):
                self.assertNotIn("Run Zig readback example", steps, msg=v)
            else:
                self.assertIn("Run Zig readback example", steps, msg=v)


# ── CLI: --check flag ───────────────────────────────────────────────────


class CheckFlagTest(unittest.TestCase):
    def test_check_passes_when_in_sync(self) -> None:
        gen_script = str(Path(__file__).resolve().parent.parent / "generate-ci.py")
        result = subprocess.run(
            [sys.executable, gen_script, "--check"],
            capture_output=True,
            text=True,
        )
        self.assertEqual(result.returncode, 0, msg=result.stdout + result.stderr)
        self.assertIn("up to date", result.stdout)


# ── Main ────────────────────────────────────────────────────────────────

if __name__ == "__main__":
    unittest.main()

